/* 确保拥有这个方法的类已经初始化 */
class_initilize( kmethod->owner_class );
/* 互斥编译 */
spin_lock( kmethod );
/* 如果已经编译了，返回 */
if( kmethod->state == JIT_STATUS_Compiled ) {
spin_unlock( kmethod );
return kmethod->jitted_code;
}
/* 现在这个线程拥有这次编译 */
kmethod->state = JIT_STATUS_Compiling;
if( ! kmethod->is_native_method ) {
funcptr = compile( kmethod );
} else { /* 从即时编译到本地代码的封装 */
funcptr = generate JAVA_to_native_stub( kmethod );
}
/* 用新的 funcptr 更新 vtable 槽，替换掉原来指向跳板代码的指针 */
method_update_vtable( kmethod, funcptr );
/* 这个方法已经编译 */
kmethod->state = JIT_STATUS_Compiled;
spin_unlock( kmethod );
return funcptr;
}
